import React from 'react';
import { Routes, Route, Navigate } from 'react-router-dom';
import { useAuth } from './context/AuthContext';
import Layout from './components/Layout';
import LoadingSpinner from './components/common/LoadingSpinner';

// Pages
import LandingPage from './pages/LandingPage';
import LoginPage from './pages/auth/LoginPage';
import StudentLogin from './pages/auth/StudentLogin';
import TeacherLogin from './pages/auth/TeacherLogin';
import AdminLogin from './pages/auth/AdminLogin';

// Dashboards
import StudentDashboard from './pages/student/StudentDashboard';
import TeacherDashboard from './pages/teacher/TeacherDashboard';
import AdminDashboard from './pages/admin/AdminDashboard';

// Student Pages
import StudentProfile from './pages/student/StudentProfile';
import StudentViolations from './pages/student/StudentViolations';
import StudentCertificates from './pages/student/StudentCertificates';

// Teacher Pages
import TeacherProfile from './pages/teacher/TeacherProfile';
import EncodeViolation from './pages/teacher/EncodeViolation';
import CapstoneManagement from './pages/teacher/CapstoneManagement';
import AdvisoryStudents from './pages/teacher/AdvisoryStudents';

// Admin Pages
import ManageStudents from './pages/admin/ManageStudents';
import ManageTeachers from './pages/admin/ManageTeachers';
import ManageViolations from './pages/admin/ManageViolations';
import SystemLogs from './pages/admin/SystemLogs';
import UserManagement from './pages/admin/UserManagement';

// Protected Route Component
const ProtectedRoute = ({ children, allowedRoles }) => {
  const { user, loading, isAuthenticated } = useAuth();

  console.log('ProtectedRoute check:', { loading, isAuthenticated, user, allowedRoles });

  if (loading) {
    console.log('ProtectedRoute: Still loading, showing spinner');
    return <LoadingSpinner />;
  }

  if (!isAuthenticated) {
    console.log('ProtectedRoute: Not authenticated, redirecting to home');
    return <Navigate to="/" replace />;
  }

  if (allowedRoles && !allowedRoles.includes(user?.role)) {
    console.log('ProtectedRoute: User role not allowed, redirecting to home. User role:', user?.role, 'Allowed roles:', allowedRoles);
    return <Navigate to="/" replace />;
  }

  console.log('ProtectedRoute: Access granted, rendering children');
  return children;
};

// Public Route (redirect if already authenticated)
const PublicRoute = ({ children }) => {
  const { user, loading, isAuthenticated } = useAuth();

  console.log('PublicRoute check:', { loading, isAuthenticated, user });

  if (loading) {
    console.log('PublicRoute: Still loading, showing spinner');
    return <LoadingSpinner />;
  }

  // Only redirect if not on the login page itself
  const currentPath = window.location.pathname;
  const isLoginPage = currentPath === '/login' || currentPath.startsWith('/login/');

  console.log('PublicRoute: Path check:', { currentPath, isLoginPage });

  if (isAuthenticated && !isLoginPage) {
    console.log('PublicRoute: Authenticated and not on login page, redirecting to dashboard. User role:', user?.role);
    // Redirect to appropriate dashboard based on role
    const role = user?.role;
    switch (role) {
      case 'student':
        return <Navigate to="/student/dashboard" replace />;
      case 'teacher':
        return <Navigate to="/teacher/dashboard" replace />;
      case 'admin':
        return <Navigate to="/admin/dashboard" replace />;
      default:
        return <Navigate to="/" replace />;
    }
  }

  console.log('PublicRoute: Rendering children');
  return children;
};

const AppRoutes = () => {
  return (
    <Routes>
      {/* Public Routes */}
      <Route path="/" element={<PublicRoute><LandingPage /></PublicRoute>} />
      <Route path="/login" element={<PublicRoute><LoginPage /></PublicRoute>} />
      <Route path="/login/:portal" element={<PublicRoute><LoginPage /></PublicRoute>} />
      <Route path="/student/login" element={<PublicRoute><StudentLogin /></PublicRoute>} />
      <Route path="/teacher/login" element={<PublicRoute><TeacherLogin /></PublicRoute>} />
      <Route path="/admin/login" element={<PublicRoute><AdminLogin /></PublicRoute>} />

      {/* Student Routes */}
      <Route path="/student" element={
        <ProtectedRoute allowedRoles={['student']}>
          <Layout role="student" />
        </ProtectedRoute>
      }>
        <Route index element={<Navigate to="/student/dashboard" replace />} />
        <Route path="dashboard" element={<StudentDashboard />} />
        <Route path="profile" element={<StudentProfile />} />
        <Route path="violations" element={<StudentViolations />} />
        <Route path="certificates" element={<StudentCertificates />} />
      </Route>

      {/* Teacher Routes */}
      <Route path="/teacher" element={
        <ProtectedRoute allowedRoles={['teacher']}>
          <Layout role="teacher" />
        </ProtectedRoute>
      }>
        <Route index element={<Navigate to="/teacher/dashboard" replace />} />
        <Route path="dashboard" element={<TeacherDashboard />} />
        <Route path="profile" element={<TeacherProfile />} />
        <Route path="encode-violation" element={<EncodeViolation />} />
        <Route path="capstone" element={<CapstoneManagement />} />
        <Route path="advisory" element={<AdvisoryStudents />} />
      </Route>

      {/* Admin Routes */}
      <Route path="/admin" element={
        <ProtectedRoute allowedRoles={['admin']}>
          <Layout role="admin" />
        </ProtectedRoute>
      }>
        <Route index element={<Navigate to="/admin/dashboard" replace />} />
        <Route path="dashboard" element={<AdminDashboard />} />
        <Route path="students" element={<ManageStudents />} />
        <Route path="teachers" element={<ManageTeachers />} />
        <Route path="violations" element={<ManageViolations />} />
        <Route path="logs" element={<SystemLogs />} />
        <Route path="users" element={<UserManagement />} />
      </Route>

      {/* Catch all - redirect to landing */}
      <Route path="*" element={<Navigate to="/" replace />} />
    </Routes>
  );
};

export default AppRoutes;
